      "if": "reference_mode == '使用上传的图片'",
      "value": "{image_reference_description}"
    },
    "final_theme_combined": {
      "if": "reference_mode == '两者结合\"",
      "value": "{theme_text} 以及来自 {image_reference_description} 的元素"
    }
  }
}

